{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>거대한 경제적 자유 — CSP Project</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Noto+Sans+KR:wght@300;400;500;700&family=DM+Mono:wght@400;500&display=swap');

:root {
  --bg: #f5f2eb;
  --surface: #ffffff;
  --ink: #1a1a1a;
  --ink2: #444444;
  --ink3: #888888;
  --accent: #c8410a;
  --accent2: #1a6b3c;
  --accent3: #1a3d6b;
  --border: #ddd8ce;
  --yellow: #f5c842;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  background: var(--bg);
  color: var(--ink);
  font-family: 'Noto Sans KR', sans-serif;
  min-height: 100vh;
  padding: 0;
}

/* ── HEADER ── */
.masthead {
  background: var(--ink);
  color: var(--bg);
  padding: 48px 48px 40px;
  position: relative;
  overflow: hidden;
}

.masthead::before {
  content: '';
  position: absolute;
  top: -40px; right: -40px;
  width: 300px; height: 300px;
  border: 1px solid rgba(245,242,235,0.08);
  border-radius: 50%;
}

.masthead::after {
  content: '';
  position: absolute;
  top: 20px; right: 20px;
  width: 180px; height: 180px;
  border: 1px solid rgba(245,242,235,0.05);
  border-radius: 50%;
}

.masthead-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 32px;
}

.masthead-label {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--accent);
  margin-bottom: 12px;
}

.masthead h1 {
  font-family: 'Bebas Neue', sans-serif;
  font-size: clamp(40px, 7vw, 80px);
  letter-spacing: 0.03em;
  line-height: 0.95;
  color: var(--bg);
}

.masthead h1 em {
  color: var(--yellow);
  font-style: normal;
}

.masthead-meta {
  text-align: right;
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  color: rgba(245,242,235,0.4);
  line-height: 2;
}

.masthead-stats {
  display: flex;
  gap: 40px;
  padding-top: 24px;
  border-top: 1px solid rgba(245,242,235,0.1);
}

.stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-num {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 32px;
  color: var(--yellow);
  line-height: 1;
}

.stat-label {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: rgba(245,242,235,0.4);
}

/* ── NAV TABS ── */
.tabs {
  display: flex;
  background: var(--ink);
  border-bottom: 2px solid var(--border);
  padding: 0 48px;
  gap: 0;
}

.tab {
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  padding: 14px 24px;
  color: rgba(245,242,235,0.35);
  cursor: pointer;
  border-bottom: 2px solid transparent;
  margin-bottom: -2px;
  transition: all 0.2s;
}

.tab:hover { color: rgba(245,242,235,0.7); }
.tab.active { color: var(--yellow); border-bottom-color: var(--yellow); }

/* ── MAIN CONTENT ── */
.content {
  padding: 48px;
}

.panel { display: none; }
.panel.active { display: block; }

/* ── VISION PANEL ── */
.vision-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 2px;
  background: var(--border);
  margin-bottom: 2px;
}

.vision-card {
  background: var(--surface);
  padding: 32px;
  position: relative;
  overflow: hidden;
}

.vision-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
}

.vision-card.newsletter::before { background: var(--accent); }
.vision-card.invest::before { background: var(--accent2); }
.vision-card.roadmap::before { background: var(--accent3); }

.vision-phase {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: var(--ink3);
  margin-bottom: 16px;
}

.vision-title {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 32px;
  letter-spacing: 0.03em;
  line-height: 1;
  color: var(--ink);
  margin-bottom: 12px;
}

.vision-card.newsletter .vision-title { color: var(--accent); }
.vision-card.invest .vision-title { color: var(--accent2); }
.vision-card.roadmap .vision-title { color: var(--accent3); }

.vision-desc {
  font-size: 13px;
  color: var(--ink2);
  line-height: 1.8;
  font-weight: 300;
  margin-bottom: 24px;
}

.vision-target {
  background: var(--bg);
  padding: 16px;
  border-left: 3px solid var(--border);
}

.vision-target-label {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--ink3);
  margin-bottom: 6px;
}

.vision-target-value {
  font-size: 14px;
  font-weight: 700;
  color: var(--ink);
}

/* 8년 로드맵 타임라인 */
.roadmap-strip {
  background: var(--surface);
  padding: 32px;
  margin-top: 2px;
}

.roadmap-label {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: var(--ink3);
  margin-bottom: 24px;
}

.roadmap-track {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2px;
  background: var(--border);
}

.roadmap-phase {
  background: var(--bg);
  padding: 20px;
}

.rp-years {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 22px;
  color: var(--ink3);
  margin-bottom: 6px;
}

.rp-name {
  font-size: 12px;
  font-weight: 700;
  color: var(--ink);
  margin-bottom: 8px;
}

.rp-goal {
  font-size: 11px;
  color: var(--ink2);
  line-height: 1.7;
  font-weight: 300;
}

.rp-milestone {
  margin-top: 12px;
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: var(--accent);
  padding: 6px 10px;
  background: rgba(200,65,10,0.06);
  border-left: 2px solid var(--accent);
}

.roadmap-phase:nth-child(2) .rp-milestone { color: var(--accent2); background: rgba(26,107,60,0.06); border-color: var(--accent2); }
.roadmap-phase:nth-child(3) .rp-milestone { color: var(--accent3); background: rgba(26,61,107,0.06); border-color: var(--accent3); }

/* ── WEEKLY TASKS PANEL ── */
.week-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 32px;
}

.week-title {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 40px;
  letter-spacing: 0.03em;
  color: var(--ink);
}

.week-subtitle {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.2em;
  color: var(--ink3);
  text-transform: uppercase;
  margin-top: 4px;
}

.week-nav {
  display: flex;
  gap: 8px;
}

.week-btn {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  padding: 8px 16px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--ink2);
  cursor: pointer;
  letter-spacing: 0.1em;
  transition: all 0.2s;
}

.week-btn:hover, .week-btn.active {
  background: var(--ink);
  color: var(--bg);
  border-color: var(--ink);
}

/* Month selector */
.month-selector {
  display: flex;
  gap: 2px;
  margin-bottom: 32px;
  background: var(--border);
  padding: 2px;
}

.month-btn {
  flex: 1;
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.1em;
  padding: 10px;
  text-align: center;
  background: var(--surface);
  cursor: pointer;
  transition: all 0.2s;
  color: var(--ink3);
  border: none;
}

.month-btn:hover { background: var(--bg); color: var(--ink); }
.month-btn.active { background: var(--ink); color: var(--yellow); }

/* Week grid */
.weeks-container { display: none; }
.weeks-container.active { display: block; }

.week-block {
  border: 1px solid var(--border);
  margin-bottom: 2px;
  background: var(--surface);
  overflow: hidden;
}

.week-block-header {
  display: grid;
  grid-template-columns: 80px 1fr auto;
  align-items: center;
  padding: 16px 20px;
  cursor: pointer;
  transition: background 0.15s;
  border-bottom: 1px solid transparent;
}

.week-block-header:hover { background: var(--bg); }
.week-block.open .week-block-header { border-bottom-color: var(--border); background: var(--bg); }

.wk-num {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 28px;
  color: var(--ink3);
  line-height: 1;
}

.wk-theme {
  font-size: 14px;
  font-weight: 700;
  color: var(--ink);
}

.wk-date {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: var(--ink3);
  letter-spacing: 0.1em;
}

.wk-toggle {
  font-size: 18px;
  color: var(--ink3);
  transition: transform 0.2s;
}

.week-block.open .wk-toggle { transform: rotate(180deg); }

.week-tasks {
  display: none;
  padding: 20px;
}

.week-block.open .week-tasks { display: block; }

.task-group {
  margin-bottom: 20px;
}

.task-group:last-child { margin-bottom: 0; }

.task-group-label {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  margin-bottom: 10px;
  padding-bottom: 6px;
  border-bottom: 1px solid var(--border);
}

.task-group.newsletter .task-group-label { color: var(--accent); }
.task-group.invest .task-group-label { color: var(--accent2); }
.task-group.habit .task-group-label { color: var(--accent3); }

.task-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 10px 0;
  border-bottom: 1px solid var(--border);
}

.task-item:last-child { border-bottom: none; }

.task-check {
  width: 18px;
  height: 18px;
  border: 1.5px solid var(--border);
  border-radius: 2px;
  flex-shrink: 0;
  margin-top: 1px;
  cursor: pointer;
  position: relative;
  transition: all 0.15s;
}

.task-check:hover { border-color: var(--ink3); }
.task-check.done { background: var(--ink); border-color: var(--ink); }
.task-check.done::after {
  content: '✓';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  color: var(--bg);
  font-size: 11px;
  font-weight: 700;
}

.task-text {
  font-size: 13px;
  color: var(--ink2);
  line-height: 1.6;
  flex: 1;
}

.task-text.done-text {
  text-decoration: line-through;
  color: var(--ink3);
}

.task-effort {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.1em;
  color: var(--ink3);
  white-space: nowrap;
  padding: 2px 6px;
  border: 1px solid var(--border);
  border-radius: 2px;
  flex-shrink: 0;
}

/* Progress bar */
.progress-section {
  background: var(--surface);
  padding: 24px;
  margin-bottom: 32px;
  border: 1px solid var(--border);
}

.progress-label {
  display: flex;
  justify-content: space-between;
  margin-bottom: 10px;
}

.progress-name {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--ink3);
}

.progress-val {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 18px;
  color: var(--ink);
}

.progress-bar {
  height: 4px;
  background: var(--border);
  margin-bottom: 16px;
  position: relative;
}

.progress-fill {
  height: 100%;
  background: var(--accent);
  transition: width 0.5s ease;
}

.progress-fill.invest { background: var(--accent2); }
.progress-fill.habit { background: var(--accent3); }

/* ── INVEST PANEL ── */
.invest-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2px;
  background: var(--border);
  margin-bottom: 2px;
}

.invest-card {
  background: var(--surface);
  padding: 32px;
}

.invest-card-label {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: var(--ink3);
  margin-bottom: 8px;
}

.invest-card-title {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 26px;
  color: var(--accent2);
  margin-bottom: 16px;
}

.invest-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
  border-bottom: 1px solid var(--border);
  font-size: 13px;
}

.invest-row:last-child { border-bottom: none; }
.invest-row-label { color: var(--ink2); font-weight: 300; }
.invest-row-val { font-weight: 700; color: var(--ink); font-family: 'DM Mono', monospace; font-size: 12px; }
.invest-row-val.highlight { color: var(--accent2); }

.gap-visual {
  background: var(--surface);
  padding: 32px;
  margin-top: 0;
}

.gap-title {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: var(--ink3);
  margin-bottom: 24px;
}

.gap-bars {
  display: flex;
  gap: 40px;
  align-items: flex-end;
  height: 120px;
  margin-bottom: 16px;
}

.gap-bar-wrap { display: flex; flex-direction: column; align-items: center; gap: 8px; flex: 1; }

.gap-bar {
  width: 100%;
  border-radius: 2px 2px 0 0;
  position: relative;
  display: flex;
  align-items: flex-end;
  justify-content: center;
}

.gap-bar-val {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 16px;
  color: white;
  padding-bottom: 6px;
}

.gap-bar-name {
  font-family: 'DM Mono', monospace;
  font-size: 9px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--ink3);
  text-align: center;
}

.gap-arrow {
  font-family: 'Bebas Neue', sans-serif;
  font-size: 28px;
  color: var(--border);
  align-self: center;
  flex: 0;
}

/* ── RESPONSIVE ── */
@media (max-width: 768px) {
  .masthead { padding: 32px 24px; }
  .content { padding: 24px; }
  .tabs { padding: 0 24px; overflow-x: auto; }
  .vision-grid { grid-template-columns: 1fr; }
  .roadmap-track { grid-template-columns: 1fr; }
  .invest-grid { grid-template-columns: 1fr; }
  .masthead-top { flex-direction: column; gap: 16px; }
  .masthead-meta { text-align: left; }
  .masthead-stats { gap: 24px; flex-wrap: wrap; }
}

/* animations */
.panel.active .vision-card,
.panel.active .invest-card,
.panel.active .week-block {
  animation: slideIn 0.3s ease forwards;
}

@keyframes slideIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}
</style>
